class Solution {
public:
    int maxSubArray(vector&lt;int&gt;&amp; nums) {
        int cur = nums[0], ans = nums[0];
        for (int i = 1; i &lt; (int)nums.size(); ++i) {
            cur = max(nums[i], cur + nums[i]);
            ans = max(ans, cur);
        }
        return ans;
